import './AboutUsScreen.css'
import React from "react";


function AboutUsScreen() {
    return(
        <div>
            <div className="initial-container">
                <div className="general-header-about">
                    <h2>About Us</h2>
                    <div className="general-header-image">
                        <div className="mask-about">

                        </div>
                    </div>


                </div>
                <div className="about-message">
                    <h4 className="about-text">The Impact Pest Guarantee means you can relax knowing we'll impact your rodent and wildlife problem and keep it impacted for as long as you keep your plan. If they do return, we will come back -- at no additional cost toional cost to you.</h4>
                </div>
            </div>
        </div>
    );
}

export default AboutUsScreen;
